const Layout: React.FC<LayoutProps> = ({ children }) => {
  // Inicializa como VISITANTE por padrão
  const [currentUser, setCurrentUser] = useState<User>({ 
      email: 'public@guest.com', name: 'Visitante', role: UserRole.GUEST, active: true 
  });
