  const location = useLocation();

  // Login Modal State
  const [isLoginOpen, setIsLoginOpen] = useState(false);
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [loginError, setLoginError] = useState('');
  const [showLoginPass, setShowLoginPass] = useState(false);

  // Change Password Modal State
  const [isChangePassOpen, setIsChangePassOpen] = useState(false);
  const [oldPass, setOldPass] = useState('');
  const [newPass, setNewPass] = useState('');
  const [confirmPass, setConfirmPass] = useState('');
  const [changePassMsg, setChangePassMsg] = useState<{type: 'error' | 'success', text: string} | null>(null);
  const [showChangePass, setShowChangePass] = useState(false);

  const [loading, setLoading] = useState(false);

  // Versão e Data (Fixos do Build via Vite env)
  // O uso de 'as any' evita erros de TS se a tipagem do vite-env não estiver configurada
  // @ts-ignore
  const appVersion = import.meta.env.VITE_APP_VERSION || '2.0.0';
  // @ts-ignore
  const buildDate = import.meta.env.VITE_BUILD_DATE || 'Data N/D';

  useEffect(() => {
    const loadUser = async () => {
      const user = await inventoryService.getCurrentUser();
      setCurrentUser(user);
      setNetworkError(inventoryService.networkErrorStatus.isError);
    };

    loadUser();
    const unsubscribe = inventoryService.subscribe(() => {
      loadUser();
    });

    return () => {
      unsubscribe();
    };
  }, []);

  const canAccess = (allowedRoles: UserRole[]) => {
    if (!currentUser) return false;
    return allowedRoles.includes(currentUser.role);
  };

  const allNavItems = [
    { name: 'Painel de Gestão', path: '/', icon: <LayoutDashboard size={20} />, roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.OPERATOR, UserRole.GUEST] },
    { name: 'Entrada / NE', path: '/entry', icon: <Box size={20} />, roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { name: 'Distribuição', path: '/distribution', icon: <ArrowUpFromLine size={20} />, roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.OPERATOR, UserRole.GUEST] },
    { name: 'Estoque Geral', path: '/inventory', icon: <PackageSearch size={20} />, roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.OPERATOR, UserRole.GUEST] },
    { name: 'Relatórios', path: '/reports', icon: <FileText size={20} />, roles: [UserRole.ADMIN, UserRole.MANAGER, UserRole.OPERATOR, UserRole.GUEST] },
    { name: 'Catálogo', path: '/catalog', icon: <Book size={20} />, roles: [UserRole.ADMIN, UserRole.MANAGER] },
    { name: 'Configurações', path: '/settings', icon: <Settings size={20} />, roles: [UserRole.ADMIN] },
  ];

  const filteredNav = allNavItems.filter(item => canAccess(item.roles));

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setLoginError('');
    const success = await inventoryService.login(loginEmail, loginPass);
    if (success) { setIsLoginOpen(false); setLoginEmail(''); setLoginPass(''); } 
    else { setLoginError('E-mail ou senha incorretos.'); }
    setLoading(false);
  };

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newPass !== confirmPass) { setChangePassMsg({ type: 'error', text: 'Senhas não conferem.' }); return; }
    if (newPass.length < 4) { setChangePassMsg({ type: 'error', text: 'Senha muito curta.' }); return; }
    setLoading(true); setChangePassMsg(null);
    const result = await inventoryService.changeOwnPassword(oldPass, newPass);
    if (result.success) { setChangePassMsg({ type: 'success', text: 'Senha alterada!' }); setTimeout(() => { setIsChangePassOpen(false); setOldPass(''); setNewPass(''); setConfirmPass(''); setChangePassMsg(null); setShowChangePass(false); }, 2000); } 
    else { setChangePassMsg({ type: 'error', text: result.message || 'Erro ao alterar.' }); }
    setLoading(false);
  };

  const handleLogout = async () => await inventoryService.logout();
  const handleRefresh = async () => await inventoryService.refreshData();
  const isGuest = currentUser?.role === UserRole.GUEST;

  return (
    <div className="flex h-screen bg-slate-100 overflow-hidden print:h-auto print:overflow-visible">
      {/* Sidebar - Desktop */}
      <aside className="hidden md:flex flex-col w-64 bg-slate-900 text-white shadow-xl z-10 print:hidden">
        <div className="p-6 border-b border-slate-700">
          <h1 className="text-lg font-bold text-sky-400 tracking-tight leading-tight">SISTEMA <span className="text-white">DTIC-PRÓ</span></h1>
          <p className="text-xs font-medium text-slate-400 mt-2 uppercase tracking-wide">Gestão de Almoxarifado</p>
          <div className="mt-3 pt-3 border-t border-slate-800">
            <p className="text-sm font-bold text-slate-200 uppercase tracking-widest">SEÇÃO LOGÍSTICA - {new Date().getFullYear()}</p>
          </div>
        </div>
        <nav className="flex-1 p-4 space-y-1">
          {filteredNav.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <Link key={item.path} to={item.path} className={`flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-medium transition-all ${isActive ? 'bg-sky-600 text-white shadow-md' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                {item.icon} {item.name}
              </Link>
            );
          })}
        </nav>
        <div className="p-4 border-t border-slate-700 bg-slate-900">
           {currentUser && !isGuest ? (
             <div className="flex flex-col gap-3">
                <div className="flex items-center gap-3 px-1">
                    <div className="w-10 h-10 rounded-full bg-slate-700 flex items-center justify-center text-sky-400 font-bold shadow-inner shrink-0"><UserIcon size={20} /></div>
                    <div className="overflow-hidden"><p className="text-sm font-bold text-white truncate" title={currentUser.name}>{currentUser.name}</p><p className="text-[10px] text-slate-400 truncate uppercase">{currentUser.role}</p></div>
                </div>
                <div className="grid grid-cols-1 gap-2 mt-1">
                    <button onClick={() => setIsChangePassOpen(true)} className="flex items-center justify-center gap-2 w-full px-3 py-2 bg-slate-800 hover:bg-sky-600 text-slate-300 hover:text-white rounded-lg transition-colors text-xs font-bold uppercase tracking-wide border border-slate-700 hover:border-sky-500" title="Alterar Senha"><KeyRound size={14} /> Alterar Senha</button>
                    <button onClick={handleLogout} className="flex items-center justify-center gap-2 w-full px-3 py-2 bg-slate-800 hover:bg-red-600 text-slate-300 hover:text-white rounded-lg transition-colors text-xs font-bold uppercase tracking-wide border border-slate-700 hover:border-red-500" title="Sair"><LogOut size={14} /> Sair</button>
                </div>
             </div>
           ) : (
             <div className="text-center"><p className="text-xs text-slate-400 mb-3 uppercase font-bold tracking-wider">Modo Visitante</p><button onClick={() => setIsLoginOpen(true)} className="w-full flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white py-3 rounded-lg text-sm font-bold transition-colors shadow-lg shadow-emerald-900/20"><LogIn size={18} /> Acessar Sistema</button></div>
           )}
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-screen overflow-hidden">
        {/* Network Error Banner */}
        {networkError && (
            <div className="bg-red-600 text-white px-6 py-3 flex items-center justify-between shadow-lg z-50 print:hidden">
                <div className="flex items-center gap-3">
                    <WifiOff className="h-6 w-6 animate-pulse" />
                    <div>
                        <p className="font-bold text-sm uppercase">Conexão com Banco de Dados Bloqueada</p>
                        <p className="text-xs opacity-90">A rede corporativa (Firewall) está impedindo o acesso ao Google Sheets. Contate o Suporte Técnico.</p>
                    </div>
                </div>
                <button onClick={handleRefresh} className="bg-white text-red-600 px-3 py-1 rounded text-xs font-bold hover:bg-red-50">Tentar Novamente</button>
            </div>
        )}

        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shadow-sm z-20 print:hidden">
           <div className="md:hidden font-bold text-slate-800 flex flex-col leading-none"><span>SISTEMA</span><span className="text-sky-600 text-sm">DTIC-PRÓ</span></div>
           <div className="flex items-center gap-3 ml-auto">
              <button onClick={handleRefresh} className="p-2 text-slate-400 hover:text-sky-600 rounded-full hover:bg-sky-50 transition-colors" title="Atualizar"><RefreshCw size={20} /></button>
              {currentUser && (
                <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold border ${isGuest ? 'bg-slate-100 text-slate-500 border-slate-200' : 'bg-sky-50 text-sky-700 border-sky-200'}`}>
                    {isGuest ? <Eye size={14} /> : <ShieldCheck size={14} />}
                    <span className="uppercase hidden sm:inline">{currentUser.role}</span>
                    {!isGuest && (<div className="flex items-center gap-2 pl-2 ml-2 border-l border-sky-200 md:hidden"><button onClick={() => setIsChangePassOpen(true)} className="text-sky-600 hover:text-sky-800"><KeyRound size={16} /></button><button onClick={handleLogout} className="text-red-500 hover:text-red-700"><LogOut size={16} /></button></div>)}
                </div>
              )}
           </div>
        </header>
        <main className="flex-1 overflow-auto p-6 md:p-8 print:p-0 print:overflow-visible flex flex-col">
            <div className="flex-1">
                {children}
            </div>

            {/* FOOTER DA VERSÃO */}
            <footer className="mt-8 pt-6 border-t border-slate-200 text-center print:hidden text-slate-500">
                <div className="flex flex-col items-center justify-center text-xs font-mono gap-1">
                    <p className="uppercase font-bold tracking-wider text-slate-400">Sistema de Controle Patrimonial DTIC-PRÓ</p>
                    <div className="flex items-center gap-2">
                        <span className="bg-slate-200 text-slate-700 px-2 py-0.5 rounded font-bold">v{appVersion}</span>
                        <span>&bull;</span>
                        <span className="font-semibold">{buildDate}</span>
                    </div>
                </div>
            </footer>
        </main>
      </div>

      {/* Modals (Login/Pass) */}
      {isLoginOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
           <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden">
              <div className="p-6 text-center bg-slate-50 border-b border-slate-100"><div className="mx-auto w-12 h-12 bg-sky-100 rounded-full flex items-center justify-center mb-4 text-sky-600"><Lock size={24} /></div><h3 className="text-xl font-bold text-slate-800">Acesso Restrito</h3></div>
              <form onSubmit={handleLogin} className="p-6 space-y-4">
                 {loginError && <div className="p-3 bg-red-50 text-red-600 text-sm rounded-lg flex items-center gap-2"><X size={16} /> {loginError}</div>}
                 <div><label className="block text-sm font-medium text-slate-700 mb-1">Usuário</label><input type="text" className="w-full p-3 bg-slate-50 border rounded-xl" value={loginEmail} onChange={e => setLoginEmail(e.target.value)} autoFocus /></div>
                 <div><label className="block text-sm font-medium text-slate-700 mb-1">Senha</label><div className="relative"><input type={showLoginPass ? "text" : "password"} className="w-full p-3 bg-slate-50 border rounded-xl pr-10" value={loginPass} onChange={e => setLoginPass(e.target.value)} /><button type="button" onClick={() => setShowLoginPass(!showLoginPass)} className="absolute right-3 top-3 text-slate-400">{showLoginPass ? <EyeOff size={18} /> : <Eye size={18} />}</button></div></div>
                 <button type="submit" disabled={loading} className="w-full py-3 bg-slate-900 text-white font-bold rounded-xl">{loading ? '...' : 'Entrar'}</button>
              </form>
              <div className="p-4 bg-slate-50 text-center border-t"><button onClick={() => setIsLoginOpen(false)} className="text-sm text-slate-500">Continuar como Visitante</button></div>
           </div>
        </div>
      )}
      {isChangePassOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden">
                <div className="p-6 flex justify-between bg-slate-50 border-b"><h3 className="font-bold flex gap-2"><KeyRound/> Senha</h3><button onClick={()=>setIsChangePassOpen(false)}><X/></button></div>
                <form onSubmit={handleChangePassword} className="p-6 space-y-4">
                    {changePassMsg && <div className={`p-3 text-sm rounded ${changePassMsg.type==='error'?'bg-red-50 text-red-600':'bg-green-50 text-green-600'}`}>{changePassMsg.text}</div>}
                    <div className="space-y-3">
                        <div><label className="block text-sm font-medium">Atual</label><div className="relative"><input type={showChangePass?"text":"password"} className="w-full p-2 border rounded" value={oldPass} onChange={e=>setOldPass(e.target.value)}/><button type="button" onClick={()=>setShowChangePass(!showChangePass)} className="absolute right-2 top-2"><Eye size={16}/></button></div></div>
                        <div><label className="block text-sm font-medium">Nova</label><input type={showChangePass?"text":"password"} className="w-full p-2 border rounded" value={newPass} onChange={e=>setNewPass(e.target.value)}/></div>
                        <div><label className="block text-sm font-medium">Confirmar</label><input type={showChangePass?"text":"password"} className="w-full p-2 border rounded" value={confirmPass} onChange={e=>setConfirmPass(e.target.value)}/></div>
                    </div>
                    <button type="submit" disabled={loading} className="w-full py-3 bg-sky-600 text-white font-bold rounded">Salvar</button>
                </form>
            </div>
        </div>
      )}
    </div>
  );
};

export default Layout;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { inventoryService } from '../services/inventoryService';
import { AlertCircle, CheckCircle, ShoppingCart, Printer, Trash2, ArrowUpFromLine, Package, UserCheck, Info, Building2, User as UserIcon, RefreshCw, Loader2, PenTool, Eraser, Layers } from 'lucide-react';
import { UserRole, User as UserType } from '../types';

interface CartItem {
  productName: string;
  requestedQty: number;
  allocations: { productId: string; neId: string; qty: number; unitValue: number; productName: string }[];
  isPossible: boolean;
}

// Interface consolidada para exibição (não mostra batches individuais na UI)
interface ConsolidatedProduct {
  name: string;
  unit: string;
  totalBalance: number;
  batches: any[]; // Mantido caso precise de debug, mas não usado na UI primária
}

const Distribution: React.FC = () => {
  const [availableProducts, setAvailableProducts] = useState<ConsolidatedProduct[]>([]);
  const [selectedProductName, setSelectedProductName] = useState('');
  const [quantity, setQuantity] = useState<number>(0);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [observation, setObservation] = useState('');
  const [receiverName, setReceiverName] = useState('');
  const [loading, setLoading] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [success, setSuccess] = useState(false);
  const [receiptData, setReceiptData] = useState<any>(null);
  const [currentUser, setCurrentUser] = useState<UserType | null>(null);

  // Assinatura Digital
  const [showSignatureModal, setShowSignatureModal] = useState(false);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  const loadData = useCallback(async () => {
     try {
      const user = await inventoryService.getCurrentUser();
      setCurrentUser(user);
      // Carrega estoque consolidado para a UI (Soma de todas as NEs)
      const stock = await inventoryService.getConsolidatedStockForDistribution();
      setAvailableProducts(stock);
     } catch (e) { console.error(e); }
  }, []);

  useEffect(() => {
    loadData();
    const unsub = inventoryService.subscribe(loadData);
    const bgSync = async () => { setIsSyncing(true); await inventoryService.refreshData(); setIsSyncing(false); };
    bgSync();
    return unsub;
  }, [loadData, success]);

  // --- ALTERAÇÃO PARA O NOME DO ARQUIVO PDF ---
  // Atualiza o título da página quando o recibo é gerado para sugerir o nome correto ao "Salvar como PDF"
  useEffect(() => {
    if (success && receiptData) {
        const originalTitle = document.title;
        // Substitui barras por hífens para ser um nome de arquivo válido (Ex: REC-001/2026 -> Recibo_REC-001-2026)
        const safeId = receiptData.id.replace(/\//g, '-');
        document.title = `Recibo_${safeId}`;

        return () => {
            document.title = originalTitle;
        };
    }
  }, [success, receiptData]);

  const handleManualRefresh = async () => {
    setIsSyncing(true);
    await inventoryService.refreshData();
    setIsSyncing(false);
  };

  const isGuest = currentUser?.role === UserRole.GUEST;

  // Encontra o produto consolidado selecionado
  const selectedProduct = availableProducts.find(p => p.name === selectedProductName);
  const maxAvailable = selectedProduct?.totalBalance || 0;
  const isQuantityValid = quantity > 0 && quantity <= maxAvailable;

  // --- CANVAS ---
  const startDrawing = (e: any) => {
    const canvas = canvasRef.current; if(!canvas)return; const ctx=canvas.getContext('2d'); if(!ctx)return;
    setIsDrawing(true); const {offsetX,offsetY} = getCoordinates(e,canvas); ctx.beginPath(); ctx.moveTo(offsetX,offsetY);
  };
  const draw = (e: any) => {
    if(!isDrawing)return; const canvas=canvasRef.current; if(!canvas)return; const ctx=canvas.getContext('2d'); if(!ctx)return;
    const {offsetX,offsetY} = getCoordinates(e,canvas); ctx.lineTo(offsetX,offsetY); ctx.stroke();
  };
  const stopDrawing = () => {
    const canvas=canvasRef.current; if(!canvas)return; const ctx=canvas.getContext('2d'); if(ctx)ctx.closePath(); setIsDrawing(false);
  };
  const getCoordinates = (e: any, canvas: HTMLCanvasElement) => {
    let clientX, clientY; if('touches' in e){ clientX=e.touches[0].clientX; clientY=e.touches[0].clientY; }else{ clientX=e.clientX; clientY=e.clientY; }
    const rect = canvas.getBoundingClientRect(); return { offsetX: clientX-rect.left, offsetY: clientY-rect.top };
  };
  const clearSignature = () => { const c=canvasRef.current; if(c) c.getContext('2d')?.clearRect(0,0,c.width,c.height); };
  const initCanvas = () => { setTimeout(() => { const c=canvasRef.current; if(c){ const ctx=c.getContext('2d'); if(ctx){ ctx.lineWidth=2; ctx.lineCap='round'; ctx.strokeStyle='black'; }}}, 100); };

  // --- ACTIONS ---
  const handleAddToDistribution = async () => {
    if (!selectedProductName || quantity <= 0 || !selectedProduct) return;
    setLoading(true);
    try {
        // AQUI ESTÁ A MÁGICA:
        // Chamamos o serviço para calcular QUAIS lotes (NEs) serão usados
        // Baseado na lógica FIFO (First-In, First-Out)
        const result = await inventoryService.calculateDistribution(selectedProductName, quantity);

        if (result.itemsToDeduct.length === 0 || result.remainingQty > 0) {
            alert('Erro de cálculo ou estoque insuficiente no momento da validação.');
            setLoading(false);
            return;
        }

        const newItem: CartItem = { 
            productName: selectedProductName, 
            requestedQty: quantity, 
            allocations: result.itemsToDeduct, // Lista de lotes quebrados (ex: 5 da NE-A, 10 da NE-B)
            isPossible: true 
        };

        setCart(prev => [...prev, newItem]); 
        setQuantity(0); 
        setSelectedProductName('');
    } catch (e) { alert('Erro ao processar adição.'); } finally { setLoading(false); }
  };

  const handleRemoveItem = (index: number) => setCart(prev => prev.filter((_, i) => i !== index));
  const handleInitiateFinalize = () => { if (cart.length > 0 && !cart.some(c=>!c.isPossible) && !isGuest) { setShowSignatureModal(true); initCanvas(); } };

  const handleConfirmSignatureAndSave = async () => {
    setLoading(true);
    try {
        let signatureDataUrl = null;
        if (canvasRef.current) signatureDataUrl = canvasRef.current.toDataURL('image/png');

        // Flat map das alocações para envio ao backend
        const allMovements: any[] = [];
        cart.forEach(item => item.allocations.forEach(alloc => allMovements.push(alloc)));

        const result = await inventoryService.executeDistribution(
          allMovements, 
          currentUser?.email || 'user@email.com', 
          observation
        );

        if (result.success) {
          const receiptId = result.receiptId || `REC-${Date.now().toString().slice(-6)}/${new Date().getFullYear()}`;
          setReceiptData({
            id: receiptId,
            date: new Date().toLocaleString('pt-BR'),
            items: cart,
            totalValue: allMovements.reduce((sum, m) => sum + (m.qty * m.unitValue), 0),
            obs: observation,
            receiverName,
            distributorName: currentUser?.name || 'Sistema',
            signature: signatureDataUrl 
          });
          setSuccess(true); setCart([]); setObservation(''); setReceiverName(''); setShowSignatureModal(false);
        }
    } catch (e) { alert('Falha ao executar.'); } 
    finally { setLoading(false); }
  };

  if (success && receiptData) {
    return (
      // Adicionado print:bg-white print:block print:p-0 para limpar o layout na impressão
      <div className="flex flex-col items-center min-h-screen bg-slate-100 pb-12 print:bg-white print:block print:min-h-0 print:pb-0 print:overflow-visible">

        {/* Adicionado print:hidden explicitamente para ocultar o cabeçalho de sucesso */}
        <div className="no-print print:hidden w-full max-w-4xl mt-8 mb-6 text-center">
          <div className="inline-flex items-center justify-center p-3 bg-emerald-100 rounded-full text-emerald-600 mb-4 shadow-sm"><CheckCircle size={32} /></div>
          <h2 className="text-2xl font-bold text-slate-800">Distribuição Realizada!</h2>
          <div className="flex justify-center gap-4 mt-6">
            <button onClick={() => window.print()} className="flex items-center gap-2 px-6 py-3 bg-slate-800 text-white rounded-lg hover:bg-slate-700 shadow-lg"><Printer size={20} /> Imprimir Recibo</button>
            <button onClick={() => { setSuccess(false); setReceiptData(null); }} className="px-6 py-3 border border-slate-300 bg-white rounded-lg hover:bg-slate-50 shadow-sm">Nova Distribuição</button>
          </div>
        </div>

        <div className="sheet-a4 bg-white shadow-2xl print:shadow-none p-[20mm] text-slate-900 box-border relative flex flex-col">
          <div className="flex items-center gap-6 border-b-2 border-black pb-6 mb-6">
            <div className="w-20 h-20 flex items-center justify-center border-2 border-black rounded-lg bg-slate-50 print:bg-transparent"><Building2 size={40} className="text-black" /></div>
            <div className="flex-1 overflow-hidden">
               <h1 className="text-base font-bold uppercase whitespace-nowrap leading-tight">POLICIA MILITAR DO ESTADO DE SÃO PAULO</h1>
               <h2 className="text-sm font-bold uppercase leading-tight mt-1">Diretoria de Tecnologia da Informação e Comunicação</h2>
               <h3 className="text-sm font-bold uppercase mt-1">Seção Logística - 2026</h3>
            </div>
            <div className="text-right shrink-0">
               <div className="border border-black px-3 py-1 rounded"><p className="text-xs font-bold uppercase">Controle Nº</p><p className="text-lg font-mono font-bold">{receiptData.id}</p></div>
            </div>
          </div>
          <div className="text-center mb-8"><h2 className="text-xl font-bold uppercase border bg-slate-100 print:bg-transparent border-black py-2 rounded">Recibo de Entrega de Material</h2></div>
          <div className="grid grid-cols-2 gap-6 mb-8 text-sm">
             <div className="border border-black p-3 rounded relative">
                <span className="absolute -top-2 left-2 bg-white px-1 text-xs font-bold uppercase">Origem / Emissor</span>
                <p><span className="font-semibold">Unidade:</span> Seção Logística - DTIC</p>
                <p><span className="font-semibold">Responsável:</span> {receiptData.distributorName}</p>
                <p><span className="font-semibold">Data de Emissão:</span> {receiptData.date}</p>
             </div>
             <div className="border border-black p-3 rounded relative">
                <span className="absolute -top-2 left-2 bg-white px-1 text-xs font-bold uppercase">Destinatário / Requisitante</span>
                <p><span className="font-semibold">Nome:</span> {receiptData.receiverName || '___________________________'}</p>
                <p><span className="font-semibold">Destino/Setor:</span> {receiptData.obs || '___________________________'}</p>
                <p><span className="font-semibold">Status:</span> <span className="uppercase">Atendido</span></p>
             </div>
          </div>
          <div className="flex-1">
            <table className="w-full border-collapse border border-black text-sm">
              <thead>
                <tr className="bg-slate-100 print:bg-slate-200 text-black">
                  <th className="border border-black px-2 py-1 w-12 text-center">#</th><th className="border border-black px-2 py-1 text-left">Descrição</th><th className="border border-black px-2 py-1 w-24 text-center">Origem (NE)</th><th className="border border-black px-2 py-1 w-20 text-right">Qtd</th><th className="border border-black px-2 py-1 w-28 text-right">Vl. Total</th>
                </tr>
              </thead>
              <tbody>
                {receiptData.items.map((item: CartItem, idx: number) => {
                  const totalItemValue = item.allocations.reduce((acc, a) => acc + (a.qty * a.unitValue), 0);
                  const nes = Array.from(new Set(item.allocations.map(a => a.neId))).join(', ');
                  return (
                    <tr key={idx}>
                      <td className="border border-black px-2 py-1 text-center">{idx + 1}</td>
                      <td className="border border-black px-2 py-1 font-semibold">{item.productName}</td>
                      <td className="border border-black px-2 py-1 text-center text-xs">{nes}</td>
                      <td className="border border-black px-2 py-1 text-right font-bold">{item.requestedQty}</td>
                      <td className="border border-black px-2 py-1 text-right">R$ {totalItemValue.toFixed(2)}</td>
                    </tr>
                  );
                })}
              </tbody>
              <tfoot>
                <tr className="bg-slate-100 print:bg-slate-200 font-bold">
                   <td colSpan={3} className="border border-black px-2 py-1 text-right uppercase">Total Geral</td>
                   <td className="border border-black px-2 py-1 text-right">{receiptData.items.reduce((acc: number, i: any) => acc + i.requestedQty, 0)}</td>
                   <td className="border border-black px-2 py-1 text-right">R$ {receiptData.totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</td>
                </tr>
              </tfoot>
            </table>
          </div>
          <div className="mt-8 border border-black p-4 rounded">
             <p className="text-xs text-justify mb-8 leading-relaxed">DECLARO ter recebido os materiais constantes neste documento em perfeitas condições de uso e conservação, assumindo a responsabilidade pela sua guarda e utilização no serviço público, comprometendo-me a comunicar imediatamente qualquer irregularidade.</p>
             <div className="flex justify-between gap-8 mt-12 mb-4 px-4 items-end">
                <div className="flex-1 text-center flex flex-col justify-end h-full pb-1">
                   <p className="font-bold uppercase text-sm">{receiptData.distributorName}</p>
                   <p className="text-xs">Almoxarifado / Expedidor</p>
                </div>
                <div className="flex-1 text-center flex flex-col items-center">
                   <div className="w-full border-b border-black mb-1 relative h-16 flex items-end justify-center">
                      {receiptData.signature ? <img src={receiptData.signature} alt="Assinatura" className="absolute bottom-0 h-20 object-contain pointer-events-none" /> : null}
                   </div>
                   <p className="font-bold uppercase text-sm">{receiptData.receiverName || '_____________________________'}</p>
                   <p className="text-xs">Recebedor</p>
                </div>
             </div>
          </div>
          <div className="mt-4 text-center text-[10px] text-slate-500">Sistema DTIC-PMESP - Emitido em {receiptData.date}</div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto">
      <header className="mb-8 flex justify-between items-end">
        <div>
            <h2 className="text-3xl font-bold text-slate-800 flex items-center gap-3"><ArrowUpFromLine className="text-accent" /> Distribuição de Material</h2>
            <p className="text-slate-500 mt-2">Saída Automática FIFO: O sistema seleciona os lotes mais antigos.</p>
        </div>
        <button onClick={handleManualRefresh} disabled={isSyncing} className={`text-sm text-sky-600 hover:underline flex items-center gap-1 ${isSyncing ? 'opacity-50' : ''}`}>{isSyncing ? <Loader2 size={14} className="animate-spin" /> : <RefreshCw size={14} />} {isSyncing ? 'Sincronizando...' : 'Atualizar Lista'}</button>
      </header>
      {isGuest && <div className="mb-6 bg-blue-50 border border-blue-200 text-blue-700 p-4 rounded-lg flex items-center gap-3"><Info /> <span className="font-medium">Modo Simulação.</span></div>}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-fit">
          <h3 className="font-bold text-lg mb-4 text-slate-700">Adicionar Produto</h3>
          {availableProducts.length === 0 && !isSyncing && <div className="bg-orange-50 border border-orange-100 text-orange-700 p-3 rounded text-sm mb-4">Sem saldo.</div>}
          <div className="space-y-4">
            <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Produto (Saldo Total)</label>
                <select className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none text-sm" value={selectedProductName} onChange={e => { setSelectedProductName(e.target.value); setQuantity(0); }}>
                    <option value="">Selecione o produto...</option>
                    {availableProducts.map((p, idx) => (
                        <option key={idx} value={p.name}>{p.name} | Total: {p.totalBalance} {p.unit}</option>
                    ))}
                </select>
                {selectedProduct && (
                    <div className="mt-2 flex flex-col gap-1 text-sm bg-blue-50 text-blue-700 p-2 rounded border border-blue-100 animate-fade-in">
                        <div className="flex items-center gap-2"><Layers size={16} /> <span>Saída: <strong>Automática (FIFO)</strong></span></div>
                        <div className="flex items-center gap-2"><Package size={16} /> <span>Disponível Total: <strong>{selectedProduct.totalBalance} {selectedProduct.unit}</strong></span></div>
                        <p className="text-xs opacity-75 mt-1">O sistema utilizará primeiro as NEs antigas.</p>
                    </div>
                )}
            </div>
            <div><label className="block text-sm font-medium text-slate-700 mb-1">Quantidade</label><input type="number" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none" value={quantity} onChange={e => setQuantity(parseInt(e.target.value) || 0)} min="0" max={maxAvailable} disabled={!selectedProductName} /></div>
            <button onClick={handleAddToDistribution} disabled={loading || !selectedProductName || !isQuantityValid} className="w-full mt-2 py-2.5 bg-accent text-white font-medium rounded-lg hover:bg-sky-600 disabled:opacity-50">Adicionar à Lista</button>
          </div>
        </div>
        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col h-full min-h-[500px]">
          <h3 className="font-bold text-lg mb-4 text-slate-700 flex items-center gap-2"><ShoppingCart size={20} /> Itens para Saída</h3>
          <div className="flex-1 overflow-y-auto space-y-4">
            {cart.length === 0 ? <div className="flex flex-col items-center justify-center h-full text-slate-400 border-2 border-dashed border-slate-200 rounded-lg"><Package size={48} className="mb-2 opacity-50" /><p>Nenhum item</p></div> : cart.map((item, idx) => {
                // Cálculo visual das NEs usadas
                const usedNEs = Array.from(new Set(item.allocations.map(a => a.neId))).join(', ');
                return (
                    <div key={idx} className={`p-4 rounded-lg border ${item.isPossible ? 'border-slate-200 bg-slate-50' : 'border-red-300 bg-red-50'}`}>
                        <div className="flex justify-between items-start mb-2">
                            <div>
                                <h4 className="font-bold text-slate-800">{item.productName}</h4>
                                <p className="text-sm text-slate-500">Qtd: {item.requestedQty} <span className="text-xs bg-slate-200 px-1 rounded ml-2">Origem: {usedNEs}</span></p>
                            </div>
                            <button onClick={() => handleRemoveItem(idx)} className="text-slate-400 hover:text-red-500"><Trash2 size={18} /></button>
                        </div>
                        {!item.isPossible ? <div className="flex items-center gap-2 text-red-600 text-sm mt-2"><AlertCircle size={16} /><span>Estoque insuficiente!</span></div> : null}
                    </div>
                );
            })}
          </div>
          <div className="mt-6 pt-6 border-t border-slate-200">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
              <div><label className="block text-sm font-medium text-slate-700 mb-1">Distribuidor</label><div className="p-2.5 bg-slate-100 border border-slate-200 rounded-lg text-slate-600 flex items-center gap-2"><UserCheck size={18} /><span className="font-medium truncate">{currentUser?.name}</span></div></div>
              <div><label className="block text-sm font-medium text-slate-700 mb-1">Recebedor</label><div className="relative"><UserIcon className="absolute left-3 top-2.5 text-slate-400" size={18} /><input type="text" className="w-full pl-10 p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none" placeholder="Quem retira" value={receiverName} onChange={e => setReceiverName(e.target.value)} /></div></div>
            </div>
            <label className="block text-sm font-medium text-slate-700 mb-2">Observações</label><input type="text" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg mb-4" placeholder="Destino..." value={observation} onChange={e => setObservation(e.target.value)} />
            <div className="flex justify-end gap-4"><button onClick={() => setCart([])} className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg">Limpar</button><button onClick={handleInitiateFinalize} disabled={loading || cart.length === 0 || cart.some(c => !c.isPossible) || isGuest} className="px-6 py-2 bg-emerald-600 text-white font-bold rounded-lg hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2">{isGuest ? 'Login Necessário' : <><CheckCircle size={18} /> Confirmar</>}</button></div>
          </div>
        </div>
      </div>
      {showSignatureModal && (
        <div className="fixed inset-0 bg-black bg-opacity-75 z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col">
                <div className="p-4 bg-slate-800 text-white flex justify-between items-center"><h3 className="font-bold flex items-center gap-2"><PenTool size={18} /> Assinatura do Recebedor</h3><button onClick={() => setShowSignatureModal(false)} className="text-slate-400 hover:text-white">✕</button></div>
                <div className="p-6 flex flex-col items-center">
                    <p className="text-sm text-slate-600 mb-4 text-center">Assine abaixo.</p>
                    <div className="border-2 border-slate-300 border-dashed bg-slate-50 rounded-lg touch-none overflow-hidden cursor-crosshair relative"><canvas ref={canvasRef} width={400} height={200} onMouseDown={startDrawing} onMouseMove={draw} onMouseUp={stopDrawing} onMouseLeave={stopDrawing} onTouchStart={startDrawing} onTouchMove={draw} onTouchEnd={stopDrawing} className="bg-white" /><div className="absolute bottom-2 right-2 text-[10px] text-slate-300 pointer-events-none select-none">Assinatura</div></div>
                    <div className="mt-6 flex gap-4 w-full"><button onClick={clearSignature} className="flex-1 py-2 border border-slate-300 text-slate-600 rounded-lg hover:bg-slate-50 flex items-center justify-center gap-2"><Eraser size={16} /> Limpar</button><button onClick={handleConfirmSignatureAndSave} disabled={loading} className="flex-1 py-2 bg-emerald-600 text-white font-bold rounded-lg hover:bg-emerald-700 flex items-center justify-center gap-2 disabled:opacity-50">{loading ? <Loader2 className="animate-spin" size={16} /> : <CheckCircle size={16} />} Salvar</button></div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};
export default Distribution;

import React, { useState, useEffect } from 'react';
import { inventoryService } from '../services/inventoryService';
import { Plus, Trash2, Save, PackagePlus, CheckCircle, Info, Lock, ShieldAlert, Search, AlertCircle, Loader2 } from 'lucide-react';
import { User, UserRole, CatalogItem } from '../types';

interface NewItem {
  name: string;
  unit: string;
  qtyPerPackage: number;
  initialQty: number;
  unitValue: number;
  minStock: number;
}

const Entry: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [pageLoading, setPageLoading] = useState(true);
  const [catalog, setCatalog] = useState<CatalogItem[]>([]);

  // NE State
  const [neNumber, setNeNumber] = useState('');
  const [supplier, setSupplier] = useState('');
  const [neDate, setNeDate] = useState(new Date().toISOString().split('T')[0]);
  const [existingNE, setExistingNE] = useState<any>(null);
  const [checkingNE, setCheckingNE] = useState(false);

  // Item Form State
  const [currentItem, setCurrentItem] = useState<NewItem>({
    name: '',
    unit: 'UN',
    qtyPerPackage: 1,
    initialQty: 0,
    unitValue: 0,
    minStock: 0
  });

  const [itemsList, setItemsList] = useState<NewItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  useEffect(() => {
    const load = async () => {
       try {
         const user = await inventoryService.getCurrentUser();
         setCurrentUser(user);
         const cat = await inventoryService.getCatalog();
         setCatalog(cat);
       } catch (e) {
         console.error(e);
       } finally {
         setPageLoading(false);
       }
    };
    load();
  }, []);

  // Verificar NE ao digitar
  useEffect(() => {
    const verifyNE = async () => {
      if (neNumber.length >= 3) {
        setCheckingNE(true);
        const data = await inventoryService.getNotaEmpenho(neNumber.toUpperCase());
        if (data) {
          setExistingNE(data);
          setSupplier(data.supplier);
          setNeDate(new Date(data.date).toISOString().split('T')[0]);
        } else {
          setExistingNE(null);
        }
        setCheckingNE(false);
      } else {
        setExistingNE(null);
      }
    };
    const timer = setTimeout(verifyNE, 500);
    return () => clearTimeout(timer);
  }, [neNumber]);

  const hasAccess = currentUser && (currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.MANAGER);

  const handleProductSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    const found = catalog.find(c => c.name === val);
    setCurrentItem(prev => ({
        ...prev,
        name: val,
        unit: found ? found.unit : prev.unit
    }));
  };

  const handleAddItem = () => {
    if (!currentItem.name || currentItem.initialQty <= 0 || currentItem.unitValue <= 0) return;
    setItemsList(prev => [...prev, currentItem]);
    setCurrentItem({
      name: '', unit: 'UN', qtyPerPackage: 1, initialQty: 0, unitValue: 0, minStock: 0
    });
  };

  const handleRemoveItem = (index: number) => {
    setItemsList(prev => prev.filter((_, i) => i !== index));
  };

  const handleSaveNE = async () => {
    if (!neNumber || !supplier || itemsList.length === 0 || !hasAccess) return;
    setLoading(true);
    try {
        const success = await inventoryService.createNotaEmpenho(
          { number: neNumber.toUpperCase(), supplier, date: neDate },
          itemsList
        );
        if (success) {
          setSuccessMsg(existingNE 
            ? `Itens adicionados à Nota de Empenho ${neNumber}!` 
            : `Nota de Empenho ${neNumber} cadastrada com sucesso!`);
          setNeNumber(''); setSupplier(''); setItemsList([]); setExistingNE(null);
          setTimeout(() => setSuccessMsg(''), 5000);
        } else {
          alert('Erro ao processar a gravação. Verifique se os dados estão corretos.');
        }
    } catch(e) { alert('Erro inesperado ao salvar.'); } 
    finally { setLoading(false); }
  };

  const totalValueNE = itemsList.reduce((acc, item) => acc + (item.initialQty * item.unitValue), 0);

  if (pageLoading) return <div className="p-8 text-center text-slate-500">Carregando...</div>;

  if (!hasAccess) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] text-center p-8">
        <div className="bg-red-50 p-6 rounded-full mb-4"><ShieldAlert className="w-16 h-16 text-red-600" /></div>
        <h2 className="text-2xl font-bold text-slate-800">Acesso Negado</h2>
        <p className="text-slate-500 mt-2 max-w-md">Seu perfil ({currentUser?.role}) não possui permissão para realizar Entradas.</p>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div>
        <h2 className="text-3xl font-bold text-slate-800 flex items-center gap-3">
          <PackagePlus className="text-emerald-600" /> Entrada de Nota de Empenho
        </h2>
        <p className="text-slate-500 mt-2">Cadastro de NE e inclusão de novos materiais ao estoque.</p>
      </div>

      {successMsg && (
        <div className="bg-emerald-50 border border-emerald-200 text-emerald-700 p-4 rounded-lg flex items-center gap-3 animate-fade-in shadow-sm">
          <CheckCircle /> <span className="font-medium">{successMsg}</span>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-lg mb-4 text-slate-700 border-b pb-2">Dados da NE</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1 flex justify-between">
                  Número da NE
                  {checkingNE && <Loader2 size={14} className="animate-spin text-sky-500" />}
                </label>
                <input type="text" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none uppercase font-bold focus:ring-2 focus:ring-sky-500" value={neNumber} onChange={e => setNeNumber(e.target.value)} placeholder="Ex: 2026NE00123" />
                {existingNE && (
                  <div className="mt-2 text-xs bg-amber-50 text-amber-700 p-2 rounded border border-amber-200 flex items-center gap-2">
                    <AlertCircle size={14} /> <span>NE já cadastrada. Novos itens serão <strong>anexados</strong> a ela.</span>
                  </div>
                )}
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Fornecedor</label>
                <input type="text" className={`w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none ${existingNE ? 'opacity-70 bg-slate-100 cursor-not-allowed' : ''}`} value={supplier} onChange={e => setSupplier(e.target.value)} disabled={!!existingNE} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Data de Emissão</label>
                <input type="date" className={`w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none ${existingNE ? 'opacity-70 bg-slate-100 cursor-not-allowed' : ''}`} value={neDate} onChange={e => setNeDate(e.target.value)} disabled={!!existingNE} />
              </div>
            </div>
          </div>
          <div className={`p-6 rounded-xl shadow-lg transition-colors ${existingNE ? 'bg-amber-600' : 'bg-slate-800'} text-white`}>
            <p className="text-sm text-white/70 mb-1">Valor Total do Lote</p>
            <p className="text-3xl font-bold font-mono">R$ {totalValueNE.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <p className="text-xs text-white/70 mt-2">{itemsList.length} itens no lote atual</p>
            <button onClick={handleSaveNE} disabled={loading || !neNumber || itemsList.length === 0} className={`mt-6 w-full py-3 ${existingNE ? 'bg-white text-amber-700 hover:bg-amber-50' : 'bg-emerald-500 hover:bg-emerald-600 text-white'} font-bold rounded-lg flex justify-center items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed transition-all`}>
              {loading ? <Loader2 className="animate-spin" /> : <><Save size={18} /> {existingNE ? 'Anexar Itens' : 'Salvar e Confirmar'}</>}
            </button>
          </div>
        </div>

        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h3 className="font-bold text-lg mb-4 text-slate-700 flex items-center gap-2"><Plus size={20} className="text-emerald-600" /> Adicionar Item</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-slate-700 mb-1">Descrição (Busque no Catálogo)</label>
                <input list="catalog-list" type="text" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-accent" value={currentItem.name} onChange={handleProductSelect} placeholder="Digite para buscar..." />
                <datalist id="catalog-list">{catalog.map((c, i) => <option key={i} value={c.name} />)}</datalist>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Unidade</label>
                <select className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none bg-slate-50" value={currentItem.unit} onChange={e => setCurrentItem({...currentItem, unit: e.target.value})}>
                  <option value="UN">UN</option><option value="CX">CX</option><option value="PCT">PCT</option><option value="KG">KG</option><option value="L">L</option><option value="RESMA">RESMA</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Qtd (Unidades)</label>
                <input type="number" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-accent" value={currentItem.initialQty} onChange={e => { const qty = parseFloat(e.target.value) || 0; setCurrentItem({ ...currentItem, initialQty: qty, minStock: Math.ceil(qty * 0.10) }); }} />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Valor Unit. (R$)</label>
                <input type="number" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none focus:ring-2 focus:ring-accent" value={currentItem.unitValue} onChange={e => setCurrentItem({...currentItem, unitValue: parseFloat(e.target.value) || 0})} />
              </div>
               <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Estoque Mín. (Sugestão 10%)</label>
                <input type="number" className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-lg outline-none text-slate-600" value={currentItem.minStock} onChange={e => setCurrentItem({...currentItem, minStock: parseFloat(e.target.value) || 0})} />
              </div>
            </div>
            <div className="flex justify-end">
              <button onClick={handleAddItem} disabled={!currentItem.name || currentItem.initialQty <= 0} className="px-6 py-2 bg-slate-800 text-white font-medium rounded-lg hover:bg-slate-700 disabled:opacity-50">Incluir Item no Lote</button>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
               <h3 className="font-bold text-slate-700">Lote de Novos Itens</h3>
               <span className="text-sm bg-slate-200 px-2 py-1 rounded text-slate-600">{itemsList.length} itens prontos</span>
            </div>
            {itemsList.length > 0 ? (
              <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 text-slate-500 font-medium border-b border-slate-200">
