  async getConsolidatedStockForDistribution() {
    const { data: products } = await supabase
      .from('products')
      .select('*')
      .gt('current_balance', 0)
      .order('created_at', { ascending: true }); // Importante: Ordena por data (Antigo -> Novo)

    if (!products) return [];

    const map = new Map();
    products.forEach((p: any) => {
      // Usa a chave normalizada para agrupar "Sabão", "Sabao" e "SABÃO" no mesmo item
      const key = this.normalizeKey(p.name);

      if (!map.has(key)) {
        map.set(key, {
            name: p.name.trim(), // Mantém o nome legível do primeiro lote encontrado
            unit: p.unit,
            totalBalance: 0,
            batches: []
        });
      }
      const item = map.get(key);
      item.totalBalance += p.current_balance;
      item.batches.push({
          id: p.id,
          neId: p.ne_id,
          currentBalance: p.current_balance,
          unitValue: p.unit_value,
          createdAt: p.created_at
      });
    });

    return Array.from(map.values()).sort((a: any, b: any) => a.name.localeCompare(b.name));
  }

