          setSuccessMsg(existingNE 
            ? `Itens adicionados à Nota de Empenho ${neNumber}!` 
            : `Nota de Empenho ${neNumber} cadastrada com sucesso!`);
          setNeNumber(''); setSupplier(''); setItemsList([]); setExistingNE(null);
          setTimeout(() => setSuccessMsg(''), 5000);
