import React, { useEffect, useState } from 'react';
import { inventoryService } from '../services/inventoryService';
import { Product } from '../types';
import { Search, Filter, ChevronLeft, ChevronRight, AlertTriangle, X } from 'lucide-react';
import { useLocation } from 'react-router-dom';

interface ConsolidatedItem {
  name: string;
  totalQty: number;
  totalValue: number;
  unit: string;
  details: Product[];
}

const Inventory: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [search, setSearch] = useState('');
  const [viewMode, setViewMode] = useState<'consolidated' | 'detailed'>('consolidated');
  const [loading, setLoading] = useState(true);

  // Filtro de Críticos
  const [showCriticalOnly, setShowCriticalOnly] = useState(false);
  const location = useLocation();

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(20);

  useEffect(() => {
    const load = async () => {
      try {
        setProducts(await inventoryService.getProducts());
      } catch (e) {
        console.error("Failed to load inventory:", e);
      } finally {
        setLoading(false);
      }
    };

    load();
    return inventoryService.subscribe(load);
  }, []);

  // Verificar se veio do Dashboard com pedido de filtro
  useEffect(() => {
    if (location.state && location.state.filterCritical) {
        setShowCriticalOnly(true);
        setViewMode('detailed'); // Força modo detalhado para ver os lotes específicos
        // Limpa o state para não ficar preso nesse filtro ao navegar de volta
        window.history.replaceState({}, document.title);
    }
  }, [location]);

  // Reset pagination when search or view mode changes
  useEffect(() => {
    setCurrentPage(1);
  }, [search, viewMode, itemsPerPage, showCriticalOnly]);

  // Filter Logic
  const filteredProducts = products.filter(p => {
    const matchesSearch = p.name.toLowerCase().includes(search.toLowerCase()) || 
                          p.neId.toLowerCase().includes(search.toLowerCase());

    const matchesCritical = showCriticalOnly ? (p.currentBalance <= p.minStock) : true;

    return matchesSearch && matchesCritical;
  });

  // Logic for Consolidated View
  const consolidated = Object.values(filteredProducts.reduce((acc, curr) => {
    if (!acc[curr.name]) {
      acc[curr.name] = {
        name: curr.name,
        totalQty: 0,
        totalValue: 0,
        unit: curr.unit,
        details: []
      };
    }
    acc[curr.name].totalQty += curr.currentBalance;
    acc[curr.name].totalValue += (curr.currentBalance * curr.unitValue);
    acc[curr.name].details.push(curr);
    return acc;
  }, {} as Record<string, ConsolidatedItem>)) as ConsolidatedItem[];

  // Determine current dataset
  const dataToRender = viewMode === 'consolidated' ? consolidated : filteredProducts;

  // Pagination Slicing
  const totalPages = Math.ceil(dataToRender.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const paginatedData = dataToRender.slice(startIndex, startIndex + itemsPerPage);

  if (loading) return <div className="p-8 text-center text-slate-500">Carregando estoque...</div>;

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-800">Estoque Geral</h2>
          <p className="text-slate-500">Consulta de saldos atuais</p>
        </div>

        <div className="flex gap-2 bg-white p-1 rounded-lg border border-slate-200 shadow-sm">
          <button 
            onClick={() => setViewMode('consolidated')}
            className={`px-4 py-1.5 rounded-md text-sm font-medium transition-colors ${viewMode === 'consolidated' ? 'bg-slate-800 text-white shadow' : 'text-slate-600 hover:bg-slate-100'}`}
          >
            Consolidado
          </button>
          <button 
             onClick={() => setViewMode('detailed')}
             className={`px-4 py-1.5 rounded-md text-sm font-medium transition-colors ${viewMode === 'detailed' ? 'bg-slate-800 text-white shadow' : 'text-slate-600 hover:bg-slate-100'}`}
          >
            Detalhado (por NE)
          </button>
        </div>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row gap-4 items-center sticky top-0 z-10">
        <div className="flex-1 flex items-center gap-2 w-full border border-slate-300 rounded-lg px-3 py-2 focus-within:ring-2 focus-within:ring-sky-500">
             <Search className="text-slate-400" />
             <input 
               type="text" 
               placeholder="Buscar por produto ou NE..." 
               className="flex-1 outline-none bg-transparent text-slate-800 placeholder-slate-400"
               value={search}
               onChange={e => setSearch(e.target.value)}
             />
        </div>

        {/* Toggle Filtro Críticos */}
        <button
            onClick={() => setShowCriticalOnly(!showCriticalOnly)}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold transition-all border ${
                showCriticalOnly 
                ? 'bg-red-50 text-red-600 border-red-200 shadow-inner' 
                : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'
            }`}
        >
            {showCriticalOnly ? <X size={16} /> : <Filter size={16} />}
            {showCriticalOnly ? 'Remover Filtro de Críticos' : 'Filtrar Críticos'}
            {showCriticalOnly && <AlertTriangle size={16} className="ml-1 fill-red-100" />}
        </button>
      </div>

      {showCriticalOnly && (
          <div className="bg-red-50 border border-red-100 p-3 rounded-lg flex items-center gap-2 text-sm text-red-700 animate-fade-in">
              <AlertTriangle size={18} />
              <span>Exibindo apenas itens com estoque abaixo ou igual ao mínimo.</span>
          </div>
      )}

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="p-4 font-semibold text-slate-600 text-sm">Produto</th>
                {viewMode === 'detailed' && <th className="p-4 font-semibold text-slate-600 text-sm">NE (Origem)</th>}
                <th className="p-4 font-semibold text-slate-600 text-sm text-center">Unidade</th>
                <th className="p-4 font-semibold text-slate-600 text-sm text-right">Saldo Atual</th>
                {viewMode === 'detailed' && <th className="p-4 font-semibold text-slate-600 text-sm text-right">Valor Unit.</th>}
                <th className="p-4 font-semibold text-slate-600 text-sm text-right">Valor Total</th>
                <th className="p-4 font-semibold text-slate-600 text-sm text-center">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {paginatedData.length === 0 ? (
                  <tr>
                      <td colSpan={7} className="p-8 text-center text-slate-400">
                          {showCriticalOnly 
                            ? "Nenhum item com estoque crítico encontrado." 
                            : "Nenhum produto cadastrado."}
                      </td>
                  </tr>
              ) : viewMode === 'consolidated' ? (
                (paginatedData as ConsolidatedItem[]).map((item, idx) => (
                  <tr key={idx} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4 font-medium text-slate-800">{item.name}</td>
                    <td className="p-4 text-center text-slate-500 text-sm">{item.unit}</td>
                    <td className="p-4 text-right font-bold text-slate-700">{item.totalQty}</td>
                    <td className="p-4 text-right text-slate-600">R$ {item.totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</td>
                    <td className="p-4 text-center">
                      {item.totalQty > 0 
                        ? <span className="inline-block w-2 h-2 rounded-full bg-emerald-500"></span>
                        : <span className="inline-block w-2 h-2 rounded-full bg-red-500"></span>
                      }
                    </td>
                  </tr>
                ))
              ) : (
                (paginatedData as Product[]).map((item) => (
                  <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                    <td className="p-4 font-medium text-slate-800">{item.name}</td>
                    <td className="p-4 text-slate-500 text-sm font-mono bg-slate-50 inline-block rounded m-2 px-2 py-1 border border-slate-200">{item.neId}</td>
                    <td className="p-4 text-center text-slate-500 text-sm">{item.unit}</td>
                    <td className={`p-4 text-right font-bold ${item.currentBalance <= item.minStock ? 'text-red-500' : 'text-slate-700'}`}>
                      {item.currentBalance}
                    </td>
                    <td className="p-4 text-right text-slate-500 text-sm">R$ {item.unitValue.toFixed(2)}</td>
                    <td className="p-4 text-right text-slate-600">R$ {(item.currentBalance * item.unitValue).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</td>
                    <td className="p-4 text-center">
                       {item.currentBalance <= item.minStock && item.currentBalance > 0 && (
                         <span className="text-xs text-orange-600 bg-orange-100 px-2 py-1 rounded-full font-medium" title={`Mínimo: ${item.minStock}`}>Baixo</span>
                       )}
                       {item.currentBalance === 0 && (
                         <span className="text-xs text-red-600 bg-red-100 px-2 py-1 rounded-full font-medium">Zerado</span>
                       )}
                       {item.currentBalance > item.minStock && (
                         <span className="text-xs text-emerald-600 bg-emerald-100 px-2 py-1 rounded-full font-medium">OK</span>
                       )}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination Controls */}
        <div className="p-4 bg-slate-50 border-t border-slate-200 flex justify-between items-center">
            <div className="text-sm text-slate-500">
                Exibindo {paginatedData.length > 0 ? startIndex + 1 : 0} a {Math.min(startIndex + itemsPerPage, dataToRender.length)} de {dataToRender.length} registros
            </div>
            <div className="flex items-center gap-2">
                <div className="mr-4">
                    <select 
                        value={itemsPerPage} 
                        onChange={(e) => { setItemsPerPage(Number(e.target.value)); }}
                        className="bg-white border border-slate-300 rounded px-2 py-1 text-sm outline-none"
                    >
                        <option value={20}>20 por página</option>
                        <option value={50}>50 por página</option>
                        <option value={100}>100 por página</option>
                    </select>
                </div>
                <button 
                    onClick={() => setCurrentPage(prev => Math.max(prev - 1, 1))}
                    disabled={currentPage === 1}
                    className="p-2 rounded hover:bg-slate-200 disabled:opacity-50 disabled:hover:bg-transparent"
                >
                    <ChevronLeft size={20} />
                </button>
                <span className="text-sm font-medium px-2">
                    Página {currentPage} de {Math.max(1, totalPages)}
                </span>
                <button 
                    onClick={() => setCurrentPage(prev => Math.min(prev + 1, totalPages))}
                    disabled={currentPage === totalPages || totalPages === 0}
                    className="p-2 rounded hover:bg-slate-200 disabled:opacity-50 disabled:hover:bg-transparent"
                >
                    <ChevronRight size={20} />
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

export default Inventory;

import React, { useState, useEffect } from 'react';
import { inventoryService } from '../services/inventoryService';
import { Plus, Trash2, Save, PackagePlus, CheckCircle, Info, Lock, ShieldAlert, Search, AlertCircle, Loader2, List, FileEdit, ChevronDown, ChevronUp, X } from 'lucide-react';
import { User, UserRole, CatalogItem, Product, NotaEmpenho } from '../types';

interface NewItem {
  name: string;
  unit: string;
  qtyPerPackage: number;
  initialQty: number;
  unitValue: number;
  minStock: number;
}

const Entry: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [pageLoading, setPageLoading] = useState(true);
  const [catalog, setCatalog] = useState<CatalogItem[]>([]);
  const [activeTab, setActiveTab] = useState<'new' | 'manage'>('new');

  // NE State (Tab New)
  const [neNumber, setNeNumber] = useState('');
  const [supplier, setSupplier] = useState('');
  const [neDate, setNeDate] = useState(new Date().toISOString().split('T')[0]);
  const [existingNE, setExistingNE] = useState<any>(null);
  const [checkingNE, setCheckingNE] = useState(false);

  // Item Form State (Tab New)
  const [currentItem, setCurrentItem] = useState<NewItem>({
    name: '', unit: 'UN', qtyPerPackage: 1, initialQty: 0, unitValue: 0, minStock: 0
  });

  const [itemsList, setItemsList] = useState<NewItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [successMsg, setSuccessMsg] = useState('');

  // Management State (Tab Manage)
  const [recentNEs, setRecentNEs] = useState<NotaEmpenho[]>([]);
  const [expandedNE, setExpandedNE] = useState<string | null>(null);
  const [neItems, setNeItems] = useState<Product[]>([]);
  const [loadingItems, setLoadingItems] = useState(false);
  const [searchManage, setSearchManage] = useState('');

  // Add Item to Existing NE State
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [targetNE, setTargetNE] = useState<NotaEmpenho | null>(null);
  const [manualItem, setManualItem] = useState<NewItem>({
    name: '', unit: 'UN', qtyPerPackage: 1, initialQty: 0, unitValue: 0, minStock: 0
  });

  useEffect(() => {
    const load = async () => {
       try {
         const user = await inventoryService.getCurrentUser();
         setCurrentUser(user);
         const cat = await inventoryService.getCatalog();
         setCatalog(cat);
       } catch (e) {
         console.error(e);
       } finally {
         setPageLoading(false);
       }
    };
    load();
  }, []);

  // Verificar NE ao digitar (Tab New)
  useEffect(() => {
    const verifyNE = async () => {
      if (neNumber.length >= 3) {
        setCheckingNE(true);
        const data = await inventoryService.getNotaEmpenho(neNumber.toUpperCase());
        if (data) {
          setExistingNE(data);
          setSupplier(data.supplier);
          setNeDate(new Date(data.date).toISOString().split('T')[0]);
        } else {
          setExistingNE(null);
        }
        setCheckingNE(false);
      } else {
        setExistingNE(null);
      }
    };
    const timer = setTimeout(verifyNE, 500);
    return () => clearTimeout(timer);
  }, [neNumber]);

  // Carregar NEs Recentes (Tab Manage)
  useEffect(() => {
    if (activeTab === 'manage') {
        const fetchNEs = async () => {
            const nes = await inventoryService.getRecentNEs();
            setRecentNEs(nes);
        };
        fetchNEs();
    }
  }, [activeTab]);

  const hasAccess = currentUser && (currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.MANAGER);
  const isAdmin = currentUser?.role === UserRole.ADMIN;

  // Handlers Tab New
  const handleProductSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    const found = catalog.find(c => c.name === val);
    setCurrentItem(prev => ({
        ...prev,
        name: val,
        unit: found ? found.unit : prev.unit
    }));
  };

  const handleAddItem = () => {
    if (!currentItem.name || currentItem.initialQty <= 0 || currentItem.unitValue <= 0) return;
    setItemsList(prev => [...prev, currentItem]);
    setCurrentItem({
      name: '', unit: 'UN', qtyPerPackage: 1, initialQty: 0, unitValue: 0, minStock: 0
    });
  };

  const handleRemoveItem = (index: number) => {
    setItemsList(prev => prev.filter((_, i) => i !== index));
  };

  const handleSaveNE = async () => {
    if (!neNumber || !supplier || itemsList.length === 0 || !hasAccess) return;
    setLoading(true);
    try {
        const success = await inventoryService.createNotaEmpenho(
          { number: neNumber.toUpperCase(), supplier, date: neDate },
          itemsList
        );
        if (success) {
          setSuccessMsg(existingNE 
            ? `Itens adicionados à Nota de Empenho ${neNumber}!` 
            : `Nota de Empenho ${neNumber} cadastrada com sucesso!`);
          setNeNumber(''); setSupplier(''); setItemsList([]); setExistingNE(null);
          setTimeout(() => setSuccessMsg(''), 5000);
        } else {
          alert('Erro ao processar a gravação. Verifique se os dados estão corretos.');
        }
    } catch(e) { alert('Erro inesperado ao salvar.'); } 
    finally { setLoading(false); }
  };

  const totalValueNE = itemsList.reduce((acc, item) => acc + (item.initialQty * item.unitValue), 0);

  // Handlers Tab Manage
  const toggleNE = async (neId: string) => {
      if (expandedNE === neId) {
          setExpandedNE(null);
          setNeItems([]);
      } else {
          setExpandedNE(neId);
          setLoadingItems(true);
          const items = await inventoryService.getProductsByNE(neId);
          setNeItems(items);
          setLoadingItems(false);
      }
  };

  const handleDeleteEntryItem = async (product: Product) => {
      if (!isAdmin) {
          alert('Apenas Administradores podem excluir registros.');
          return;
      }
      if (!window.confirm(`ATENÇÃO ADMIN: Tem certeza que deseja excluir "${product.name}"?\n\nO valor será estornado da NE e as movimentações de entrada serão apagadas.`)) return;

      const result = await inventoryService.deleteProductEntry(product.id);
      if (result.success) {
          // Atualiza a lista local
          const updatedItems = neItems.filter(p => p.id !== product.id);
          setNeItems(updatedItems);

          // Se não houver mais itens, a NE foi excluída no backend, atualizar lista de NEs
          if (updatedItems.length === 0) {
              setRecentNEs(prev => prev.filter(n => n.id !== product.neId));
              setExpandedNE(null);
          } else {
              // Atualiza valor visual da NE na lista
              const valueRemoved = product.initialQty * product.unitValue;
              setRecentNEs(prev => prev.map(n => n.id === product.neId ? { ...n, totalValue: Math.max(0, n.totalValue - valueRemoved) } : n));
          }
          alert(result.message);
      } else {
          alert(result.message);
      }
  };

  // --- Handlers para Adicionar Item em NE Existente ---

  const handleOpenAddModal = (ne: NotaEmpenho) => {
    setTargetNE(ne);
    setManualItem({ name: '', unit: 'UN', qtyPerPackage: 1, initialQty: 0, unitValue: 0, minStock: 0 });
    setIsAddModalOpen(true);
  };

  const handleManualProductSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    const found = catalog.find(c => c.name === val);
    setManualItem(prev => ({
        ...prev,
        name: val,
        unit: found ? found.unit : prev.unit
    }));
  };

  const handleSaveItemToExistingNE = async () => {
      if (!targetNE || !manualItem.name || manualItem.initialQty <= 0) return;

      setLoading(true);
      try {
          // Reutiliza a função createNotaEmpenho. Como o ID já existe, ela apenas adiciona itens e atualiza o total.
          const success = await inventoryService.createNotaEmpenho(
              { number: targetNE.id, supplier: targetNE.supplier, date: targetNE.date },
              [manualItem]
          );

          if (success) {
              alert('Item adicionado com sucesso!');
              setIsAddModalOpen(false);

              // Atualiza a lista de itens da NE aberta
              setLoadingItems(true);
              const updatedItems = await inventoryService.getProductsByNE(targetNE.id);
              setNeItems(updatedItems);
              setLoadingItems(false);

              // Atualiza o valor total na lista de NEs
              const updatedNEs = await inventoryService.getRecentNEs();
              setRecentNEs(updatedNEs);
          } else {
              alert('Erro ao adicionar item.');
          }
      } catch (e) {
          console.error(e);
          alert('Erro ao processar.');
      } finally {
          setLoading(false);
      }
  };

  if (pageLoading) return <div className="p-8 text-center text-slate-500">Carregando...</div>;

  if (!hasAccess) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] text-center p-8">
        <div className="bg-red-50 p-6 rounded-full mb-4"><ShieldAlert className="w-16 h-16 text-red-600" /></div>
        <h2 className="text-2xl font-bold text-slate-800">Acesso Negado</h2>
        <p className="text-slate-500 mt-2 max-w-md">Seu perfil ({currentUser?.role}) não possui permissão para realizar Entradas.</p>
      </div>
    );
  }

  const filteredNEs = recentNEs.filter(ne => ne.id.includes(searchManage.toUpperCase()) || ne.supplier.toLowerCase().includes(searchManage.toLowerCase()));

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-bold text-slate-800 flex items-center gap-3">
            <PackagePlus className="text-emerald-600" /> Entrada de Nota de Empenho
          </h2>
          <p className="text-slate-500 mt-2">Cadastro de NE e inclusão de novos materiais ao estoque.</p>
        </div>
      </div>

      <div className="flex gap-4 border-b border-slate-200">
          <button 
             onClick={() => setActiveTab('new')}
             className={`px-4 py-2 font-medium border-b-2 transition-colors ${activeTab === 'new' ? 'border-emerald-500 text-emerald-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
             Nova Entrada
          </button>
          <button 
             onClick={() => setActiveTab('manage')}
             className={`px-4 py-2 font-medium border-b-2 transition-colors ${activeTab === 'manage' ? 'border-emerald-500 text-emerald-700' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
          >
             Gerenciar/Corrigir Entradas
          </button>
      </div>

      {activeTab === 'new' ? (
        <>
            {successMsg && (
                <div className="bg-emerald-50 border border-emerald-200 text-emerald-700 p-4 rounded-lg flex items-center gap-3 animate-fade-in shadow-sm">
                <CheckCircle /> <span className="font-medium">{successMsg}</span>
                </div>
            )}

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-1 space-y-6">
